#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e5+5;
int a[MAXN],b[MAXN],m,n,ans=0;
signed main(void)
{
	n=read(),m=read();
	FOR(i,1,n)
	{
		a[i]=read();
	}
	FOR(i,1,m)
	{
		b[i]=read();
	}
	sort(a+1,a+n+1);
	FOR(i,1,m)
	{
		int l=0,r=n+1;
		wh(l<r)
		{
			if(a[mid]<=b[i])l=mid+1;
			else r=mid;
		}
		if(b[i]<=a[1])
		{
			ans+=abs(a[1]-b[i]);
		}
		else
		{
			ans+=min(abs(a[l-1]-b[i]),abs(a[l]-b[i]));
		} 
	}
	write(ans);
    return false;
}
